    wire is_zero_a = (exp_a==1'd0) && (mant_a==2'd0);
    wire is_zero_b = (exp_b==1'd0) && (mant_b==2'd0);
    wire is_inf_a  = (exp_a==EXP_MAX) && (mant_a==2'd0);
    wire is_inf_b  = (exp_b==EXP_MAX) && (mant_b==2'd0);
