    localparam [3:0] NEG_INF = {1'b1, EXP_MAX, 2'd0};
    localparam [3:0] QNAN    = {1'b1, EXP_MAX, 2'd1};

    reg signed [3:0] exp_product;
    reg [5:0] mant_product;          // 2M+2 = 6-bit product
    reg [2:0]  norm;                  // {leading1, M mantissa bits}
    reg          guard;

    always @(*) begin
        if (is_nan_a || is_nan_b)                 result = QNAN;
        else if (is_inf_a && is_zero_b)           result = QNAN;
        else if (is_inf_b && is_zero_a)           result = QNAN;
        else if (is_inf_a || is_inf_b)            result = result_sign ? NEG_INF : POS_INF;
        else if (is_zero_a || is_zero_b)          result = {result_sign, 3'd0};
        else begin
            exp_product  = $signed({ 3'b0, exp_a}) + $signed({ 3'b0, exp_b}) - $signed({ 3'b0, BIAS});
            mant_product = {1'b1, mant_a} * {1'b1, mant_b};
