                exp_product = exp_product + 4'sd1;
                norm  = {1'b1, mant_product[4:3]};
                guard = mant_product[2];
            end else begin                                 // [1,2): leading 1 at bit 4
                norm  = {1'b1, mant_product[3:2]};
                guard = mant_product[1];
            end
            if (guard) norm = norm + 3'd1;
            if (norm == 3'd0) exp_product = exp_product + 4'sd1;
            if (exp_product <= 0)
                result = {result_sign, 3'd0};
            else if (exp_product >= $signed({ 3'b0, EXP_MAX}))
